package mcp

import (
	"context"
	"fmt"
	"log/slog"
	"strings"

	"github.com/google/uuid"
	mcpgo "github.com/mark3labs/mcp-go/mcp"
	"github.com/mark3labs/mcp-go/server"

	"github.com/ketang/flotsam/api/internal/item"
)

const (
	defaultSearchLimit     = 10
	maxSearchLimit         = 50
	defaultSearchThreshold = 0.3
)

// --- search tool ---

func searchTool() mcpgo.Tool {
	return mcpgo.NewTool("search",
		mcpgo.WithDescription("Search your knowledge base. Returns matching items with titles, types, tags, and content snippets."),
		mcpgo.WithString("query", mcpgo.Required(), mcpgo.Description("Search query text")),
		mcpgo.WithNumber("limit", mcpgo.Description("Max results to return (1-50, default 10)")),
		mcpgo.WithString("type", mcpgo.Description("Filter by item type"), mcpgo.Enum("bookmark", "text_note", "voice_note")),
	)
}

func searchHandler(deps Deps) server.ToolHandlerFunc {
	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
		claims, errResult := requireAuth(ctx)
		if errResult != nil {
			return errResult, nil
		}

		query := req.GetString("query", "")
		if query == "" {
			return mcpgo.NewToolResultError("query is required"), nil
		}

		limit := req.GetInt("limit", defaultSearchLimit)
		if limit < 1 {
			limit = 1
		}
		if limit > maxSearchLimit {
			limit = maxSearchLimit
		}

		var filter *item.Filter
		if t := req.GetString("type", ""); t != "" {
			filter = &item.Filter{Types: []string{t}}
		}

		result, err := doSearch(ctx, deps, claims.UserID, query, filter, limit)
		if err != nil {
			return mcpgo.NewToolResultError(fmt.Sprintf("search failed: %v", err)), nil
		}

		return mcpgo.NewToolResultText(formatSearchResults(result)), nil
	}
}

// doSearch tries semantic search first, falling back to full-text search.
func doSearch(ctx context.Context, deps Deps, ownerID uuid.UUID, query string, filter *item.Filter, limit int) (*item.SearchResult, error) {
	if deps.Embedder != nil {
		embedding, err := deps.Embedder.Embed(ctx, query)
		if err != nil {
			slog.WarnContext(ctx, "mcp: embedding failed, falling back to FTS", "error", err)
		} else {
			result, err := deps.Items.SemanticSearch(ctx, ownerID, embedding, filter, limit, defaultSearchThreshold)
			if err == nil && len(result.Items) > 0 {
				return result, nil
			}
			if err != nil {
				slog.WarnContext(ctx, "mcp: semantic search failed, falling back to FTS", "error", err)
			}
		}
	}

	return deps.Items.Search(ctx, ownerID, query, filter, limit, 0)
}

// --- browse tool ---

func browseTool() mcpgo.Tool {
	return mcpgo.NewTool("browse",
		mcpgo.WithDescription("Get the full content of an item by its ID."),
		mcpgo.WithString("id", mcpgo.Required(), mcpgo.Description("Item UUID")),
	)
}

func browseHandler(deps Deps) server.ToolHandlerFunc {
	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
		claims, errResult := requireAuth(ctx)
		if errResult != nil {
			return errResult, nil
		}

		idStr := req.GetString("id", "")
		id, err := uuid.Parse(idStr)
		if err != nil {
			return mcpgo.NewToolResultError("invalid item ID: must be a valid UUID"), nil
		}

		it, err := deps.Items.GetByID(ctx, claims.UserID, id)
		if err != nil {
			return mcpgo.NewToolResultError(fmt.Sprintf("failed to get item: %v", err)), nil
		}

		return mcpgo.NewToolResultText(formatItem(it)), nil
	}
}

// --- capture tool ---

func captureTool() mcpgo.Tool {
	return mcpgo.NewTool("capture",
		mcpgo.WithDescription("Capture a new item into your knowledge base. Provide 'url' for a bookmark or 'content' for a note."),
		mcpgo.WithString("url", mcpgo.Description("URL to bookmark")),
		mcpgo.WithString("content", mcpgo.Description("Text content for a note")),
		mcpgo.WithString("title", mcpgo.Description("Optional title")),
		mcpgo.WithString("tags", mcpgo.Description("Comma-separated tags")),
		mcpgo.WithString("sensitivity", mcpgo.Description("Sensitivity level"), mcpgo.Enum("normal", "sensitive")),
	)
}

func captureHandler(deps Deps) server.ToolHandlerFunc {
	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
		claims, errResult := requireAuth(ctx)
		if errResult != nil {
			return errResult, nil
		}

		url := req.GetString("url", "")
		content := req.GetString("content", "")
		titleStr := req.GetString("title", "")
		tagsStr := req.GetString("tags", "")
		sensitivity := req.GetString("sensitivity", "normal")

		var title *string
		if titleStr != "" {
			title = &titleStr
		}

		var tags []string
		if tagsStr != "" {
			for _, t := range strings.Split(tagsStr, ",") {
				t = strings.TrimSpace(t)
				if t != "" {
					tags = append(tags, t)
				}
			}
		}

		switch {
		case url != "":
			it, err := deps.Items.CaptureBookmark(ctx, claims.UserID, item.BookmarkInput{
				URL:         url,
				Title:       title,
				Tags:        tags,
				Sensitivity: sensitivity,
				Source:      "mcp",
			})
			if err != nil {
				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture bookmark: %v", err)), nil
			}
			return mcpgo.NewToolResultText(formatItem(it)), nil

		case content != "":
			it, err := deps.Items.CaptureNote(ctx, claims.UserID, item.NoteInput{
				Title:       title,
				Content:     content,
				Tags:        tags,
				Sensitivity: sensitivity,
				Source:      "mcp",
			})
			if err != nil {
				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture note: %v", err)), nil
			}
			return mcpgo.NewToolResultText(formatItem(it)), nil

		default:
			return mcpgo.NewToolResultError("either 'url' (for bookmark) or 'content' (for note) is required"), nil
		}
	}
}

package mcp

import (
	"context"
	"net/http"

	mcpgo "github.com/mark3labs/mcp-go/mcp"
	"github.com/mark3labs/mcp-go/server"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/version"
)

// NewHandler creates an MCP HTTP handler with search, browse, and capture tools.
func NewHandler(deps Deps) http.Handler {
	s := server.NewMCPServer(
		"flotsam",
		version.Version,
		server.WithToolCapabilities(false),
	)

	s.AddTool(searchTool(), searchHandler(deps))
	s.AddTool(browseTool(), browseHandler(deps))
	s.AddTool(captureTool(), captureHandler(deps))

	httpServer := server.NewStreamableHTTPServer(s,
		server.WithStateLess(true),
		server.WithHTTPContextFunc(func(ctx context.Context, r *http.Request) context.Context {
			if claims := auth.GetClaims(r.Context()); claims != nil {
				ctx = auth.WithClaims(ctx, claims)
			}
			return ctx
		}),
	)

	return httpServer
}

// requireAuth extracts claims from context, returning an error result if unauthenticated.
func requireAuth(ctx context.Context) (*auth.Claims, *mcpgo.CallToolResult) {
	claims := auth.GetClaims(ctx)
	if claims == nil {
		return nil, mcpgo.NewToolResultError("authentication required")
	}
	return claims, nil
}

package mcp

import (
	"context"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/internal/item"
)

// ItemSearcher abstracts the item.Service methods the MCP server needs.
type ItemSearcher interface {
	GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*item.Item, error)
	Search(ctx context.Context, ownerID uuid.UUID, query string, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error)
	SemanticSearch(ctx context.Context, ownerID uuid.UUID, embedding []float32, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error)
	CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input item.BookmarkInput) (*item.Item, error)
	CaptureNote(ctx context.Context, ownerID uuid.UUID, input item.NoteInput) (*item.Item, error)
}

// Embedder generates vector embeddings for search queries.
type Embedder interface {
	Embed(ctx context.Context, text string) ([]float32, error)
	Dimensions() int
}

// Deps holds MCP server dependencies.
type Deps struct {
	Items    ItemSearcher
	Embedder Embedder // nil if embedding not configured
}

package router

import (
	"encoding/json"
	"log/slog"
	"net/http"
	"strings"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/cors"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/graph/generated"
	"github.com/ketang/flotsam/api/graph/resolver"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/item"
	flotsammcp "github.com/ketang/flotsam/api/internal/mcp"
	flotsammiddleware "github.com/ketang/flotsam/api/internal/middleware"
	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
	"github.com/ketang/flotsam/api/internal/user"
	"github.com/ketang/flotsam/api/internal/version"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config      *config.Config
	Pool        *pgxpool.Pool
	Validator   auth.Validator
	Storage     *storage.Client // nil if S3 not configured
	RiverClient *river.Client[pgx.Tx]
	Items       *item.Service
	Users       *user.Service
	Issuer      *auth.Issuer
	Embedder    provider.Embedder // nil if no embedding provider configured
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Global middleware (applied to every request)
	r.Use(flotsammiddleware.RequestID)
	r.Use(flotsammiddleware.Logging)
	r.Use(flotsammiddleware.Recovery)
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// CORS (if configured)
	if deps.Config.CORSOrigins != "" {
		origins := parseCORSOrigins(deps.Config.CORSOrigins)
		r.Use(cors.Handler(cors.Options{
			AllowedOrigins:   origins,
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
			AllowedHeaders:   []string{"Accept", "Authorization", "Content-Type"},
			AllowCredentials: true,
			MaxAge:           300,
		}))
	}

	// Health endpoint — no auth
	r.Get("/health", healthHandler)

	// GraphQL handler
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{
			ItemService: deps.Items,
			UserService: deps.Users,
			Issuer:      deps.Issuer,
			RiverClient: deps.RiverClient,
			Storage:     deps.Storage,
			Embedder:    deps.Embedder,
		},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth + rate limit
	r.Route("/graphql", func(r chi.Router) {
		r.Use(flotsammiddleware.OptionalAuth(deps.Validator))
		if deps.Config.RateLimitEnabled {
			rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitGraphQL)
			r.Use(rl.Limit)
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// GraphQL playground (dev only)
	if deps.Config.GQLPlayground {
		r.Get("/playground", playground.Handler("Flotsam API", "/graphql"))
		slog.Info("router: GraphQL playground enabled at /playground")
	}

	// MCP endpoint — mandatory auth + rate limit
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(flotsammiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitMCP)
				r.Use(rl.Limit)
			}
			mcpHandler := flotsammcp.NewHandler(flotsammcp.Deps{
			Items:    deps.Items,
			Embedder: deps.Embedder,
		})
		r.Handle("/*", mcpHandler)
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// Upload endpoint — mandatory auth
	r.Route("/upload", func(r chi.Router) {
		r.Use(flotsammiddleware.Auth(deps.Validator))
		r.Post("/", uploadHandler(deps.Storage, deps.Config.MaxUploadSize))
	})

	slog.Info("router: initialized",
		"cors_origins", deps.Config.CORSOrigins,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
	)

	return r
}

func healthHandler(w http.ResponseWriter, _ *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]string{
		"status":  "ok",
		"version": version.Version,
	})
}

func parseCORSOrigins(s string) []string {
	parts := strings.Split(s, ",")
	origins := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			origins = append(origins, p)
		}
	}
	return origins
}

