package auth

import (
	"errors"
	"fmt"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
)

// Claims extends jwt.RegisteredClaims with application-specific fields.
type Claims struct {
	jwt.RegisteredClaims
	UserID     uuid.UUID `json:"uid"`
	Email      string    `json:"email,omitempty"`
	ClientType string    `json:"ctype,omitempty"` // web|cli|mobile
}

// Validator validates a JWT token string and returns parsed claims.
type Validator interface {
	Validate(tokenString string) (*Claims, error)
}

// HMACValidator validates HS256 tokens using a shared secret.
type HMACValidator struct {
	secret []byte
}

// NewHMACValidator creates a Validator using HS256 with the provided secret.
func NewHMACValidator(secret string) *HMACValidator {
	return &HMACValidator{secret: []byte(secret)}
}

// Validate parses and validates an HS256 JWT token string.
func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
	claims := &Claims{}
	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
		}
		return v.secret, nil
	})
	if err != nil {
		return nil, fmt.Errorf("auth: token validation failed: %w", err)
	}
	if !token.Valid {
		return nil, errors.New("auth: token is not valid")
	}
	return claims, nil
}

