	if result != "No items found." {
		t.Errorf("expected 'No items found.', got %q", result)
	}
}

func TestFormatSearchResults_WithItems(t *testing.T) {
	it := testItem()
	result := formatSearchResults(searchResult(it))
	if !strings.Contains(result, "Test Item") {
		t.Error("expected result to contain item title")
	}
	if !strings.Contains(result, "bookmark") {
		t.Error("expected result to contain item type")
	}
