package audit

import (
	"context"
	"encoding/json"
	"log/slog"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
)

// Logger provides best-effort append-only audit logging.
type Logger struct {
	pool *pgxpool.Pool
}

// New creates an audit Logger.
func New(pool *pgxpool.Pool) *Logger {
	return &Logger{pool: pool}
}

// Entry represents a single audit log entry.
type Entry struct {
	UserID          uuid.UUID
	ClientID        *uuid.UUID
	Action          string
	ResourceType    string
	ResourceID      *uuid.UUID
	Request         map[string]any
	ResponseSummary map[string]any
	Approved        *bool
}

// Log writes an audit entry. Errors are logged but never returned — audit
// logging must not block the request path.
func (l *Logger) Log(ctx context.Context, e Entry) {
	reqJSON, err := json.Marshal(e.Request)
	if err != nil {
		slog.ErrorContext(ctx, "audit: marshal request", "error", err)
		return
	}

	var respJSON []byte
	if e.ResponseSummary != nil {
		respJSON, err = json.Marshal(e.ResponseSummary)
		if err != nil {
			slog.ErrorContext(ctx, "audit: marshal response_summary", "error", err)
			return
		}
	}

	query := `INSERT INTO audit_log (user_id, client_id, action, resource_type, resource_id, request, response_summary, approved)
		VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`

	_, err = l.pool.Exec(ctx, query,
		e.UserID, e.ClientID, e.Action, e.ResourceType, e.ResourceID,
		reqJSON, respJSON, e.Approved,
	)
	if err != nil {
		slog.ErrorContext(ctx, "audit: insert failed", "action", e.Action, "error", err)
	}
}

