package mcp

import (
	"context"
	"fmt"
	"log/slog"
	"strings"

	"github.com/google/uuid"
	mcpgo "github.com/mark3labs/mcp-go/mcp"
	"github.com/mark3labs/mcp-go/server"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/audit"
	"github.com/ketang/flotsam/api/internal/item"
)

const (
	defaultSearchLimit     = 10
	maxSearchLimit         = 50
	defaultSearchThreshold = 0.3
)

// --- search tool ---

func searchTool() mcpgo.Tool {
	return mcpgo.NewTool("search",
		mcpgo.WithDescription("Search your knowledge base. Returns matching items with titles, types, tags, and content snippets."),
		mcpgo.WithString("query", mcpgo.Required(), mcpgo.Description("Search query text")),
		mcpgo.WithNumber("limit", mcpgo.Description("Max results to return (1-50, default 10)")),
		mcpgo.WithString("type", mcpgo.Description("Filter by item type"), mcpgo.Enum("bookmark", "text_note", "voice_note")),
	)
}

func searchHandler(deps Deps) server.ToolHandlerFunc {
	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
		claims, errResult := requireAuth(ctx)
		if errResult != nil {
			return errResult, nil
		}

		if errResult := AllowedTool(ctx, "search"); errResult != nil {
			auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), true)
			return errResult, nil
		}

		query := req.GetString("query", "")
		if query == "" {
			return mcpgo.NewToolResultError("query is required"), nil
		}

		limit := req.GetInt("limit", defaultSearchLimit)
		if limit < 1 {
			limit = 1
		}
		if limit > maxSearchLimit {
			limit = maxSearchLimit
		}

		var filter *item.Filter
		if t := req.GetString("type", ""); t != "" {
			filter = &item.Filter{Types: []string{t}}
		}

		result, err := doSearch(ctx, deps, claims.UserID, query, filter, limit)
		if err != nil {
			auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), false)
			return mcpgo.NewToolResultError(fmt.Sprintf("search failed: %v", err)), nil
		}

		// Filter results by sensitivity
		result = FilterItemsBySensitivity(ctx, result)

		auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), false)
		return mcpgo.NewToolResultText(formatSearchResults(result)), nil
	}
}

// doSearch tries semantic search first, falling back to full-text search.
func doSearch(ctx context.Context, deps Deps, ownerID uuid.UUID, query string, filter *item.Filter, limit int) (*item.SearchResult, error) {
	if deps.Embedder != nil {
		embedding, err := deps.Embedder.Embed(ctx, query)
		if err != nil {
			slog.WarnContext(ctx, "mcp: embedding failed, falling back to FTS", "error", err)
		} else {
			result, err := deps.Items.SemanticSearch(ctx, ownerID, embedding, filter, limit, defaultSearchThreshold)
			if err == nil && len(result.Items) > 0 {
				return result, nil
			}
			if err != nil {
				slog.WarnContext(ctx, "mcp: semantic search failed, falling back to FTS", "error", err)
			}
		}
	}

	return deps.Items.Search(ctx, ownerID, query, filter, limit, 0)
}

// --- browse tool ---

func browseTool() mcpgo.Tool {
	return mcpgo.NewTool("browse",
		mcpgo.WithDescription("Get the full content of an item by its ID."),
		mcpgo.WithString("id", mcpgo.Required(), mcpgo.Description("Item UUID")),
	)
}

func browseHandler(deps Deps) server.ToolHandlerFunc {
	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
		claims, errResult := requireAuth(ctx)
		if errResult != nil {
			return errResult, nil
		}

		if errResult := AllowedTool(ctx, "browse"); errResult != nil {
			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), true)
			return errResult, nil
		}

		idStr := req.GetString("id", "")
		id, err := uuid.Parse(idStr)
		if err != nil {
			return mcpgo.NewToolResultError("invalid item ID: must be a valid UUID"), nil
		}

		it, err := deps.Items.GetByID(ctx, claims.UserID, id)
		if err != nil {
			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), false)
			return mcpgo.NewToolResultError(fmt.Sprintf("failed to get item: %v", err)), nil
		}

		// Check sensitivity
		if !SensitivityAllowed(ctx, it.Sensitivity) {
			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), true)
			return mcpgo.NewToolResultError("item sensitivity level exceeds API key permissions"), nil
		}

		auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), false)
		return mcpgo.NewToolResultText(formatItem(it)), nil
	}
}

// --- capture tool ---

func captureTool() mcpgo.Tool {
	return mcpgo.NewTool("capture",
		mcpgo.WithDescription("Capture a new item into your knowledge base. Provide 'url' for a bookmark or 'content' for a note."),
		mcpgo.WithString("url", mcpgo.Description("URL to bookmark")),
		mcpgo.WithString("content", mcpgo.Description("Text content for a note")),
		mcpgo.WithString("title", mcpgo.Description("Optional title")),
		mcpgo.WithString("tags", mcpgo.Description("Comma-separated tags")),
		mcpgo.WithString("sensitivity", mcpgo.Description("Sensitivity level"), mcpgo.Enum("normal", "sensitive")),
	)
}

func captureHandler(deps Deps) server.ToolHandlerFunc {
	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
		claims, errResult := requireAuth(ctx)
		if errResult != nil {
			return errResult, nil
		}

		if errResult := AllowedTool(ctx, "capture"); errResult != nil {
			auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), true)
			return errResult, nil
		}

		url := req.GetString("url", "")
		content := req.GetString("content", "")
		titleStr := req.GetString("title", "")
		tagsStr := req.GetString("tags", "")
		sensitivity := req.GetString("sensitivity", "normal")

		var title *string
		if titleStr != "" {
			title = &titleStr
		}

		var tags []string
		if tagsStr != "" {
			for _, t := range strings.Split(tagsStr, ",") {
				t = strings.TrimSpace(t)
				if t != "" {
					tags = append(tags, t)
				}
			}
		}

		switch {
		case url != "":
			it, err := deps.Items.CaptureBookmark(ctx, claims.UserID, item.BookmarkInput{
				URL:         url,
				Title:       title,
				Tags:        tags,
				Sensitivity: sensitivity,
				Source:      "mcp",
			})
			if err != nil {
				auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture bookmark: %v", err)), nil
			}
			auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
			return mcpgo.NewToolResultText(formatItem(it)), nil

		case content != "":
			it, err := deps.Items.CaptureNote(ctx, claims.UserID, item.NoteInput{
				Title:       title,
				Content:     content,
				Tags:        tags,
				Sensitivity: sensitivity,
				Source:      "mcp",
			})
			if err != nil {
				auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture note: %v", err)), nil
			}
			auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
			return mcpgo.NewToolResultText(formatItem(it)), nil

		default:
			return mcpgo.NewToolResultError("either 'url' (for bookmark) or 'content' (for note) is required"), nil
		}
	}
}

// auditToolCall logs a tool invocation to the audit log (best effort).
func auditToolCall(ctx context.Context, logger *audit.Logger, claims *auth.Claims, tool string, args map[string]any, denied bool) {
	if logger == nil {
		return
	}

	client := auth.GetMCPClient(ctx)
	var clientID *uuid.UUID
	if client != nil {
		clientID = &client.ClientID
	}

	var approved *bool
	if denied {
		f := false
		approved = &f
	}

	logger.Log(ctx, audit.Entry{
		UserID:       claims.UserID,
		ClientID:     clientID,
		Action:       "mcp." + tool,
		ResourceType: "tool",
		Request:      args,
		Approved:     approved,
	})
}

