			return mcpgo.NewToolResultError("either 'url' (for bookmark) or 'content' (for note) is required"), nil
		}
	}
}

// auditToolCall logs a tool invocation to the audit log (best effort).
func auditToolCall(ctx context.Context, logger *audit.Logger, claims *auth.Claims, tool string, args map[string]any, denied bool) {
	if logger == nil {
		return
	}

	client := auth.GetMCPClient(ctx)
	var clientID *uuid.UUID
	if client != nil {
		clientID = &client.ClientID
	}

	var approved *bool
	if denied {
		f := false
		approved = &f
	}

	logger.Log(ctx, audit.Entry{
		UserID:       claims.UserID,
		ClientID:     clientID,
		Action:       "mcp." + tool,
		ResourceType: "tool",
		Request:      args,
		Approved:     approved,
	})
}

