package router

import (
	"encoding/json"
	"log/slog"
	"net/http"
	"strings"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/cors"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/graph/generated"
	"github.com/ketang/flotsam/api/graph/resolver"
	"github.com/ketang/flotsam/api/internal/audit"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/item"
	flotsammcp "github.com/ketang/flotsam/api/internal/mcp"
	"github.com/ketang/flotsam/api/internal/mcpclient"
	flotsammiddleware "github.com/ketang/flotsam/api/internal/middleware"
	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
	"github.com/ketang/flotsam/api/internal/user"
	"github.com/ketang/flotsam/api/internal/version"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config      *config.Config
	Pool        *pgxpool.Pool
	Validator   auth.Validator
	Storage     *storage.Client // nil if S3 not configured
	RiverClient *river.Client[pgx.Tx]
	Items       *item.Service
	Users       *user.Service
	Issuer      *auth.Issuer
	Embedder    provider.Embedder        // nil if no embedding provider configured
	MCPClients  *mcpclient.Service       // nil if MCP not enabled
	Audit       *audit.Logger            // nil if audit logging not configured
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Global middleware (applied to every request)
	r.Use(flotsammiddleware.RequestID)
	r.Use(flotsammiddleware.Logging)
	r.Use(flotsammiddleware.Recovery)
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// CORS (if configured)
	if deps.Config.CORSOrigins != "" {
		origins := parseCORSOrigins(deps.Config.CORSOrigins)
		r.Use(cors.Handler(cors.Options{
			AllowedOrigins:   origins,
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
			AllowedHeaders:   []string{"Accept", "Authorization", "Content-Type"},
			AllowCredentials: true,
			MaxAge:           300,
		}))
	}

	// Health endpoint — no auth
	r.Get("/health", healthHandler)

	// GraphQL handler
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{
			ItemService: deps.Items,
			UserService: deps.Users,
			Issuer:      deps.Issuer,
			RiverClient: deps.RiverClient,
			Storage:     deps.Storage,
			Embedder:    deps.Embedder,
		},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth + rate limit
	r.Route("/graphql", func(r chi.Router) {
		r.Use(flotsammiddleware.OptionalAuth(deps.Validator))
		if deps.Config.RateLimitEnabled {
			rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitGraphQL)
			r.Use(rl.Limit)
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// GraphQL playground (dev only)
	if deps.Config.GQLPlayground {
		r.Get("/playground", playground.Handler("Flotsam API", "/graphql"))
		slog.Info("router: GraphQL playground enabled at /playground")
	}

	// MCP endpoint — mandatory auth + rate limit
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(flotsammiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitMCP)
				r.Use(rl.Limit)
			}
			mcpHandler := flotsammcp.NewHandler(flotsammcp.Deps{
			Items:    deps.Items,
			Embedder: deps.Embedder,
		})
		r.Handle("/*", mcpHandler)
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// Upload endpoint — mandatory auth
	r.Route("/upload", func(r chi.Router) {
		r.Use(flotsammiddleware.Auth(deps.Validator))
		r.Post("/", uploadHandler(deps.Storage, deps.Config.MaxUploadSize))
	})

	slog.Info("router: initialized",
		"cors_origins", deps.Config.CORSOrigins,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
	)

	return r
}

func healthHandler(w http.ResponseWriter, _ *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]string{
		"status":  "ok",
		"version": version.Version,
	})
}

func parseCORSOrigins(s string) []string {
	parts := strings.Split(s, ",")
	origins := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			origins = append(origins, p)
		}
	}
	return origins
}

package main

import (
	"context"
	"flag"
	"log/slog"
	"os"
	"os/exec"
	"os/signal"
	"syscall"

	"github.com/joho/godotenv"
	"github.com/riverqueue/river"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
	"github.com/ketang/flotsam/api/internal/item"
	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/router"
	"github.com/ketang/flotsam/api/internal/server"
	"github.com/ketang/flotsam/api/internal/storage"
	"github.com/ketang/flotsam/api/internal/user"
	"github.com/ketang/flotsam/api/internal/version"
)

func main() {
	withWorker := flag.Bool("with-worker", false, "fork flotsam-worker --watch as a child process")
	flag.Parse()

	// 1. Load .env (no-op if file is absent — dev convenience only)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting flotsam api",
		"version", version.Version,
		"build_time", version.BuildTime,
		"env", cfg.Env,
	)

	// 4. Connect to database
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error
	}
	defer pool.Close()

	// 5. Initialize S3 storage client (optional)
	var store *storage.Client
	if cfg.S3Endpoint != "" {
		store, err = storage.New(storage.Config{
			Endpoint:       cfg.S3Endpoint,
			Bucket:         cfg.S3Bucket,
			AccessKey:      cfg.S3AccessKey,
			SecretKey:      cfg.S3SecretKey,
			Region:         cfg.S3Region,
			ForcePathStyle: cfg.S3ForcePathStyle,
		})
		if err != nil {
			slog.Error("failed to initialize storage", "error", err)
			os.Exit(1) //nolint:gocritic // fatal startup error
		}
		slog.Info("storage: S3 client initialized", "endpoint", cfg.S3Endpoint, "bucket", cfg.S3Bucket)
	} else {
		slog.Warn("storage: S3_ENDPOINT not set, object storage disabled")
	}

	// 6. Initialize River client (insert-only — no workers, no queues)
	riverClient, err := river.NewClient(riverpgxv5.New(pool), &river.Config{})
	if err != nil {
		slog.Error("failed to create river client", "error", err)
		os.Exit(1)
	}
	slog.Info("river: insert-only client initialized")

	// 7. Initialize auth validator
	validator := auth.NewHMACValidator(cfg.JWTSecret)
	slog.Info("auth: using HS256 JWT validator")

	// 8. Initialize services
	itemService := item.New(pool)
	userService := user.New(pool)
	issuer := auth.NewIssuer(cfg.JWTSecret, cfg.JWTExpiry)

	// 8b. Initialize embedding provider (optional)
	var embedder provider.Embedder
	if cfg.OpenAIAPIKey != "" {
		opts := []provider.OpenAIEmbedderOption{}
		if cfg.EmbeddingModel != "" {
			opts = append(opts, provider.WithEmbeddingModel(cfg.EmbeddingModel))
		}
		cloudEmbedder := provider.NewOpenAIEmbedder(cfg.OpenAIAPIKey, opts...)
		slog.Info("provider: OpenAI embedder initialized", "model", cfg.EmbeddingModel)

		if cfg.OllamaURL != "" {
			localEmbedder := provider.NewOllamaEmbedder(cfg.OllamaURL,
				provider.WithOllamaEmbeddingModel(cfg.OllamaEmbeddingModel))
			embedder = provider.NewRoutingEmbedder(cloudEmbedder, localEmbedder)
			slog.Info("provider: Ollama embedder initialized (routing enabled)", "model", cfg.OllamaEmbeddingModel)
		} else {
			embedder = cloudEmbedder
		}
	} else if cfg.OllamaURL != "" {
		embedder = provider.NewOllamaEmbedder(cfg.OllamaURL,
			provider.WithOllamaEmbeddingModel(cfg.OllamaEmbeddingModel))
		slog.Info("provider: Ollama embedder initialized (local only)", "model", cfg.OllamaEmbeddingModel)
	}

	// 9. Build router
	r := router.New(router.Deps{
		Config:      cfg,
		Pool:        pool,
		Validator:   validator,
		Storage:     store,
		RiverClient: riverClient,
		Items:       itemService,
		Users:       userService,
		Issuer:      issuer,
		Embedder:    embedder,
	})

	// 9. Optionally fork worker as child process
	var workerCmd *exec.Cmd
	if *withWorker {
		workerCmd = exec.Command("flotsam-worker", "--watch")
		workerCmd.Stdout = os.Stdout
		workerCmd.Stderr = os.Stderr
		if err := workerCmd.Start(); err != nil {
			slog.Error("failed to start worker", "error", err)
		} else {
			slog.Info("worker: started as child process", "pid", workerCmd.Process.Pid)
		}
	}

	// 10. Start HTTP server
	srv := server.New(cfg.Addr(), r)

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		slog.Info("server: listening", "addr", cfg.Addr())
		if err := srv.Start(); err != nil {
			slog.Info("server: stopped", "reason", err)
		}
	}()

	// 11. Block until signal received
	sig := <-sigCh
	slog.Info("signal received", "signal", sig)

	// 12. Graceful shutdown
	shutdownCtx, cancel := context.WithTimeout(context.Background(), cfg.ShutdownTimeout)
	defer cancel()

	slog.Info("server: shutting down", "timeout", cfg.ShutdownTimeout)
	if err := srv.Shutdown(shutdownCtx); err != nil {
		slog.Error("server: shutdown error", "error", err)
		os.Exit(1)
	}

	// Kill worker child process if running
	if workerCmd != nil && workerCmd.Process != nil {
		slog.Info("worker: stopping child process", "pid", workerCmd.Process.Pid)
		_ = workerCmd.Process.Signal(syscall.SIGTERM)
		_ = workerCmd.Wait()
	}

	slog.Info("server: shutdown complete")
}

