	if len(filtered.Items) != 1 {
		t.Fatalf("expected 1 item, got %d", len(filtered.Items))
	}
}

func TestFilterItemsBySensitivity_JWTAuth_NoPrivate(t *testing.T) {
	ctx := authedCtx()
	normalItem := testItem()
	sensitiveItem := testItem()
	sensitiveItem.Sensitivity = "sensitive"
	privateItem := testItem()
	privateItem.Sensitivity = "private"

	result := &item.SearchResult{
		Items: []*item.Item{normalItem, sensitiveItem, privateItem},
		Total: 3,
	}

	filtered := FilterItemsBySensitivity(ctx, result)
	if len(filtered.Items) != 2 {
		t.Fatalf("expected 2 items, got %d", len(filtered.Items))
	}
}

