func TestAuthWithAPIKey_ValidAPIKey(t *testing.T) {
	ownerID := uuid.New()
	clientID := uuid.New()
	v := &mockValidator{}
	clients := &mockMCPClientLookup{
		client: &mcpclient.Client{
			ID:      clientID,
			OwnerID: ownerID,
			Name:    "test-client",
			Active:  true,
			Permissions: mcpclient.Permissions{
				Tools:          []string{"search"},
				MaxSensitivity: "normal",
			},
		},
	}

	var gotClaims *auth.Claims
	var gotMCPClient *auth.MCPClientInfo
	inner := http.HandlerFunc(func(_ http.ResponseWriter, r *http.Request) {
		gotClaims = auth.GetClaims(r.Context())
		gotMCPClient = auth.GetMCPClient(r.Context())
	})

	handler := AuthWithAPIKey(v, clients)(inner)
	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("Authorization", "Bearer flt_test-api-key")

	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
	if gotClaims == nil {
		t.Fatal("claims not set")
	}
	if gotClaims.UserID != ownerID {
		t.Errorf("claims.UserID = %v, want %v", gotClaims.UserID, ownerID)
	}
	if gotClaims.ClientType != "mcp" {
		t.Errorf("claims.ClientType = %q, want %q", gotClaims.ClientType, "mcp")
	}
	if gotMCPClient == nil {
		t.Fatal("MCPClientInfo not set")
	}
	if gotMCPClient.ClientID != clientID {
		t.Errorf("MCPClient.ClientID = %v, want %v", gotMCPClient.ClientID, clientID)
	}
	if gotMCPClient.Name != "test-client" {
		t.Errorf("MCPClient.Name = %q, want %q", gotMCPClient.Name, "test-client")
	}
}

