package auth

import (
	"context"
	"testing"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
)

const testSecret = "test-secret-key-for-hmac-validation"

func makeHMACToken(t *testing.T, secret string, claims Claims) string {
	t.Helper()
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	signed, err := token.SignedString([]byte(secret))
	if err != nil {
		t.Fatalf("failed to sign token: %v", err)
	}
	return signed
}

func TestHMACValidator_ValidToken(t *testing.T) {
	uid := uuid.New()
	tokenStr := makeHMACToken(t, testSecret, Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   uid.String(),
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
		},
		UserID:     uid,
		Email:      "test@example.com",
		ClientType: "web",
	})

	v := NewHMACValidator(testSecret)
	claims, err := v.Validate(tokenStr)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if claims.UserID != uid {
		t.Errorf("UserID = %v, want %v", claims.UserID, uid)
	}
	if claims.Email != "test@example.com" {
		t.Errorf("Email = %q, want %q", claims.Email, "test@example.com")
	}
	if claims.ClientType != "web" {
		t.Errorf("ClientType = %q, want %q", claims.ClientType, "web")
	}
}

func TestHMACValidator_ExpiredToken(t *testing.T) {
	tokenStr := makeHMACToken(t, testSecret, Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(-time.Hour)),
		},
	})

	v := NewHMACValidator(testSecret)
	_, err := v.Validate(tokenStr)
	if err == nil {
		t.Fatal("expected error for expired token")
	}
}

func TestHMACValidator_WrongSecret(t *testing.T) {
	tokenStr := makeHMACToken(t, testSecret, Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
		},
	})

	v := NewHMACValidator("wrong-secret")
	_, err := v.Validate(tokenStr)
	if err == nil {
		t.Fatal("expected error for wrong secret")
	}
}

func TestHMACValidator_MalformedToken(t *testing.T) {
	v := NewHMACValidator(testSecret)
	_, err := v.Validate("not-a-jwt")
	if err == nil {
		t.Fatal("expected error for malformed token")
	}
}

func TestHMACValidator_RSASignedToken(t *testing.T) {
	// An HS256 validator should reject tokens signed with a different method.
	// We simulate this by creating a token that claims RS256 but is actually nonsense.
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
		},
	})
	// Override the header to claim RS256
	token.Header["alg"] = "RS256"
	// Sign with HMAC secret (the header lies about the algorithm)
	signed, err := token.SignedString([]byte(testSecret))
	if err != nil {
		t.Fatalf("failed to sign token: %v", err)
	}

	v := NewHMACValidator(testSecret)
	_, err = v.Validate(signed)
	if err == nil {
		t.Fatal("expected error for RS256-header token validated by HMAC validator")
	}
}

func TestWithAndGetClaims(t *testing.T) {
	claims := &Claims{Email: "user@example.com"}
	ctx := WithClaims(context.Background(), claims)

	got := GetClaims(ctx)
	if got == nil {
		t.Fatal("GetClaims returned nil")
	}
	if got.Email != "user@example.com" {
		t.Errorf("Email = %q, want %q", got.Email, "user@example.com")
	}
}

func TestGetClaims_NoClaims(t *testing.T) {
	got := GetClaims(context.Background())
	if got != nil {
		t.Errorf("GetClaims on empty context = %v, want nil", got)
	}
}

